// ---- HELPERS ----
function fmtDate(s) {
  if (!s) return '';
  const d = new Date(s);
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric', timeZone: 'America/Los_Angeles' });
}
function parseDate(s) {
  // Parse a DB date to a local-midnight Date for day-diff math
  const d = new Date(s);
  const ds = d.toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' });
  return new Date(ds + 'T00:00:00');
}
function fmtTime(s) {
  if (!s) return '';
  const [h, m] = s.split(':').map(Number);
  const ampm = h >= 12 ? 'PM' : 'AM';
  const h12 = h % 12 || 12;
  return m === 0 ? `${h12} ${ampm}` : `${h12}:${String(m).padStart(2, '0')} ${ampm}`;
}

// ---- HELPERS: deduplicate by id ----
function dedup(items) {
  const seen = new Set();
  return items.filter(i => {
    const id = i.json.id;
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });
}

// ---- TIMEZONE-AWARE TODAY ----
// n8n task runner uses UTC; derive today from Pacific time
const TZ = 'America/Los_Angeles';
const nowPacific = new Date().toLocaleDateString('en-CA', { timeZone: TZ }); // 'YYYY-MM-DD'
const today = new Date(nowPacific + 'T00:00:00');

// ---- PROCESS TRIPS ----
const tripRows = dedup($('Query Trips').all());

const trips = [];
for (const item of tripRows) {
  const trip = item.json;
  if (!trip.start_date) continue;
  const startDate = parseDate(trip.start_date);
  const daysRemaining = Math.round((startDate - today) / (1000 * 60 * 60 * 24));
  if (daysRemaining > 30) continue;

  const t30 = typeof trip.tier_30 === 'string' ? JSON.parse(trip.tier_30) : (trip.tier_30 || {});
  const t7 = typeof trip.tier_7 === 'string' ? JSON.parse(trip.tier_7) : (trip.tier_7 || {});
  const t1 = typeof trip.tier_1 === 'string' ? JSON.parse(trip.tier_1) : (trip.tier_1 || {});

  let tierData = {};
  if (daysRemaining <= 1) {
    tierData = { ...t30, ...t7, ...t1 };
  } else if (daysRemaining <= 7) {
    tierData = { ...t30, ...t7 };
  } else {
    tierData = { ...t30 };
  }

  trips.push({ title: trip.title, destination: trip.destination, start_date: trip.start_date, end_date: trip.end_date, days_remaining: daysRemaining, tierData, notes: trip.notes });
}

// ---- PROCESS RECURRING EVENTS ----
const recurringRows = dedup($('Query Recurring').all());
const tomorrow = new Date(today);
tomorrow.setDate(tomorrow.getDate() + 1);
const dayMap = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];
const dayLabels = { mon: 'Mon', tue: 'Tue', wed: 'Wed', thu: 'Thu', fri: 'Fri', sat: 'Sat', sun: 'Sun' };
const todayDay = dayMap[today.getDay()];
const tomorrowDay = dayMap[tomorrow.getDay()];

const recurring = [];
for (const item of recurringRows) {
  const ev = item.json;
  if (!ev.days) continue;
  const days = Array.isArray(ev.days) ? ev.days : (typeof ev.days === 'string' ? ev.days.replace(/[{}]/g, '').split(',') : []);
  const evStart = parseDate(ev.start_date);
  const evEnd = parseDate(ev.end_date);
  const daysUntilStart = Math.round((evStart - today) / (1000 * 60 * 60 * 24));
  const daysList = days.map(d => dayLabels[d] || d).join(' & ');

  if (daysUntilStart > 1) {
    recurring.push({ title: ev.title, location: ev.location, start_time: ev.start_time, end_time: ev.end_time, start_date: ev.start_date, end_date: ev.end_date, daysList, reminders: [{ type: 'countdown', label: `Starts in ${daysUntilStart} days` }], notes: ev.notes });
    continue;
  }

  const reminders = [];
  if (ev.remind_morning_of !== false && days.includes(todayDay) && today >= evStart && today <= evEnd) {
    reminders.push({ type: 'today', label: 'Today' });
  }
  if (ev.remind_day_before !== false && days.includes(tomorrowDay) && tomorrow >= evStart && tomorrow <= evEnd) {
    reminders.push({ type: 'tomorrow', label: 'Tomorrow' });
  }
  if (daysUntilStart === 1) {
    reminders.push({ type: 'countdown', label: 'Starts tomorrow' });
  }
  if (reminders.length > 0) {
    recurring.push({ title: ev.title, location: ev.location, start_time: ev.start_time, end_time: ev.end_time, start_date: ev.start_date, end_date: ev.end_date, daysList, reminders, notes: ev.notes });
  }
}

// ---- PROCESS MAINTENANCE ----
const maintenanceRows = dedup($('Query Maintenance').all());
const maintenance = [];
for (const item of maintenanceRows) {
  const m = item.json;
  if (!m.last_performed || !m.frequency_days) continue;
  const lastPerformed = parseDate(m.last_performed);
  const nextDue = new Date(lastPerformed);
  nextDue.setDate(nextDue.getDate() + m.frequency_days);
  const daysUntilDue = Math.round((nextDue - today) / (1000 * 60 * 60 * 24));

  maintenance.push({
    title: m.title, category: m.category, frequency_days: m.frequency_days,
    last_performed: m.last_performed, next_due: nextDue.toISOString().split('T')[0],
    days_until_due: daysUntilDue, is_overdue: daysUntilDue <= 0,
    is_due_soon: daysUntilDue > 0 && daysUntilDue <= 7, priority: m.priority, notes: m.notes
  });
}
maintenance.sort((a, b) => a.days_until_due - b.days_until_due);

// ---- CHECK IF ANY CONTENT ----
const hasContent = trips.length > 0 || recurring.length > 0 || maintenance.length > 0;
if (!hasContent) {
  return [{ json: { hasContent: false } }];
}

// ---- BUILD HTML ----
const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: TZ });

let html = `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>
<body style="margin:0;padding:0;background-color:#f4f4f7;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:#f4f4f7;">
<tr><td align="center" style="padding:24px 16px;">
<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06);">
<tr><td style="background-color:#1a1a2e;color:#ffffff;padding:24px 32px;">
  <h1 style="margin:0;font-size:22px;font-weight:600;">Daily Digest &mdash; ${dateStr}</h1>
  <p style="margin:8px 0 0;font-size:14px;color:#a0a0b8;">Your reminders for today</p>
</td></tr>`;

if (trips.length > 0) {
  html += `<tr><td style="padding:24px 32px 8px;"><h2 style="margin:0;font-size:16px;color:#6c63ff;text-transform:uppercase;letter-spacing:1px;">Upcoming Trips</h2></td></tr>`;
  for (const d of trips) {
    const td = d.tierData || {};
    html += `<tr><td style="padding:8px 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #e8e8ef;border-radius:8px;overflow:hidden;"><tr>`;
    html += `<td width="80" style="background-color:#6c63ff;color:#fff;text-align:center;vertical-align:middle;padding:16px 8px;"><div style="font-size:28px;font-weight:700;line-height:1;">${d.days_remaining}</div><div style="font-size:11px;text-transform:uppercase;margin-top:4px;">days</div></td>`;
    html += `<td style="padding:16px;"><div style="font-size:16px;font-weight:600;color:#1a1a2e;">${d.title}</div>`;
    html += `<div style="font-size:13px;color:#6b7280;margin-top:4px;">${fmtDate(d.start_date)} &rarr; ${fmtDate(d.end_date)}${d.destination ? ' &middot; ' + d.destination : ''}</div>`;
    if (td.summary) html += `<div style="margin-top:8px;font-size:13px;color:#374151;">${td.summary}</div>`;
    if (td.hotel) html += `<div style="margin-top:4px;font-size:13px;color:#374151;"><strong>Hotel:</strong> ${td.hotel}</div>`;
    if (td.packing_list) html += `<div style="margin-top:12px;padding:12px;background:#f0f0ff;border-radius:6px;font-size:13px;"><strong>Packing List:</strong><br>${td.packing_list}</div>`;
    if (td.flight_info) html += `<div style="margin-top:8px;padding:12px;background:#f0fdf4;border-radius:6px;font-size:13px;"><strong>Flight:</strong> ${td.flight_info}</div>`;
    if (td.car_rental) html += `<div style="margin-top:8px;padding:12px;background:#fefce8;border-radius:6px;font-size:13px;"><strong>Car Rental:</strong> ${td.car_rental}</div>`;
    if (td.itinerary) html += `<div style="margin-top:8px;padding:12px;background:#fffbeb;border-radius:6px;font-size:13px;"><strong>Itinerary:</strong><br>${td.itinerary.replace(/\n/g, '<br>')}</div>`;
    if (td.checklist) html += `<div style="margin-top:8px;padding:12px;background:#fef2f2;border-radius:6px;font-size:13px;"><strong>Checklist:</strong> ${td.checklist}</div>`;
    html += `</td></tr></table></td></tr>`;
  }
}

if (recurring.length > 0) {
  html += `<tr><td style="padding:24px 32px 8px;"><h2 style="margin:0;font-size:16px;color:#059669;text-transform:uppercase;letter-spacing:1px;">Recurring Events</h2></td></tr>`;
  for (const d of recurring) {
    html += `<tr><td style="padding:8px 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #e8e8ef;border-radius:8px;"><tr><td style="padding:16px;">`;
    html += `<div style="font-size:16px;font-weight:600;color:#1a1a2e;">${d.title}`;
    for (const rem of d.reminders) {
      const bg = rem.type === 'today' ? '#dcfce7' : rem.type === 'tomorrow' ? '#dbeafe' : '#f3f0ff';
      const color = rem.type === 'today' ? '#166534' : rem.type === 'tomorrow' ? '#1e40af' : '#6c63ff';
      html += ` <span style="display:inline-block;margin-left:8px;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;background:${bg};color:${color};">${rem.label}</span>`;
    }
    html += `</div>`;
    html += `<div style="font-size:13px;color:#6b7280;margin-top:4px;">${fmtTime(d.start_time)} &ndash; ${fmtTime(d.end_time)}`;
    if (d.daysList) html += ` &middot; ${d.daysList}`;
    if (d.location) html += ` &middot; ${d.location}`;
    html += `</div>`;
    if (d.start_date && d.end_date) html += `<div style="font-size:12px;color:#9ca3af;margin-top:2px;">${fmtDate(d.start_date)} &ndash; ${fmtDate(d.end_date)}</div>`;
    html += `</td></tr></table></td></tr>`;
  }
}

if (maintenance.length > 0) {
  html += `<tr><td style="padding:24px 32px 8px;"><h2 style="margin:0;font-size:16px;color:#dc2626;text-transform:uppercase;letter-spacing:1px;">Maintenance Tracker</h2></td></tr>`;
  for (const d of maintenance) {
    const borderColor = d.is_overdue ? '#fca5a5' : '#e8e8ef';
    const bgColor = d.is_overdue ? 'background-color:#fef2f2;' : '';
    html += `<tr><td style="padding:8px 32px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ${borderColor};border-radius:8px;${bgColor}"><tr><td style="padding:16px;">`;
    html += `<div style="font-size:16px;font-weight:600;color:#1a1a2e;">${d.title}`;
    if (d.is_overdue) {
      html += ` <span style="display:inline-block;margin-left:8px;padding:3px 10px;border-radius:4px;font-size:11px;font-weight:700;background-color:#dc2626;color:#ffffff;">DUE NOW</span>`;
    } else if (d.is_due_soon) {
      html += ` <span style="display:inline-block;margin-left:8px;padding:3px 10px;border-radius:4px;font-size:11px;font-weight:700;background-color:#f59e0b;color:#ffffff;">DUE SOON</span>`;
    }
    html += `</div>`;
    html += `<div style="font-size:13px;color:#6b7280;margin-top:4px;">Last done: ${fmtDate(d.last_performed)} &middot; Due: ${fmtDate(d.next_due)} &middot; Every ${d.frequency_days} days`;
    if (d.category) html += ` &middot; ${d.category}`;
    html += `</div></td></tr></table></td></tr>`;
  }
}

html += `<tr><td style="padding:24px 32px;text-align:center;font-size:12px;color:#9ca3af;border-top:1px solid #e8e8ef;">Generated by your n8n Reminder Service &middot; ${dateStr}</td></tr>`;
html += `</table></td></tr></table></body></html>`;

const subject = [
  trips.length > 0 ? `${trips.length} trip(s)` : null,
  recurring.length > 0 ? `${recurring.length} event(s)` : null,
  maintenance.filter(m => m.is_overdue).length > 0 ? `${maintenance.filter(m => m.is_overdue).length} overdue` : null
].filter(Boolean).join(', ');

return [{ json: { hasContent: true, subject: `Daily Digest: ${subject}`, html, trip_count: trips.length, recurring_count: recurring.length, maintenance_count: maintenance.length } }];
